#include<bits/stdc++.h>
using namespace std;
int n,m,k,a[21][21],f[21][401][21][21][2][2];
struct node
{
    int i,j,l,r,x,y;
}pre[21][401][21][21][2][2];
void print(node x)
{
    if(x.j==0)
    {
        return;
    }
    print(pre[x.i][x.j][x.l][x.r][x.x][x.y]);
    for(int i=x.l;i<=x.r;i++)
    {
        printf("%d %d\n",x.i,i);
    }
}
int main()
{
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            scanf("%d",&a[i][j]);
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=k;j++)
        {
            for(int l=1;l<=m;l++)
            {
                for(int r=l;r<=m;r++)
                {
                    int val=0,add=0;
                    for(int k=l;k<=r;k++)
                    {
                        val+=a[i][k];
                    }
                    if(j<r-l+1)
                    {
                        continue;
                    }
                    for(int p=l;p<=r;p++)
                    {
                        for(int q=p;q<=r;q++)
                        {
                            int tmp=f[i-1][j-(r-l+1)][p][q][1][0];
                            if(tmp>add)
                            {
                                add=tmp;
                                pre[i][j][l][r][1][0]=(node){i-1,j-(r-l+1),p,q,1,0};
                            }
                        }
                    }
                    f[i][j][l][r][1][0]=val+add;
                    add=0;
                    for(int p=l;p<=r;p++)
                    {
                        for(int q=r;q<=m;q++)
                        {
                            for(int y=0;y<=1;y++)
                            {
                                int tmp=f[i-1][j-(r-l+1)][p][q][1][y];
                                if(tmp>add)
                                {
                                    add=tmp;
                                    pre[i][j][l][r][1][1]=(node){i-1,j-(r-l+1),p,q,1,y};
                                }
                            }
                        }
                    }
                    f[i][j][l][r][1][1]=val+add;
                    add=0;
                    for(int p=1;p<=l;p++)
                    {
                        for(int q=l;q<=r;q++)
                        {
                            for(int x=0;x<=1;x++)
                            {
                                int tmp=f[i-1][j-(r-l+1)][p][q][x][0];
                                if(tmp>add)
                                {
                                    add=tmp;
                                    pre[i][j][l][r][0][0]=(node){i-1,j-(r-l+1),p,q,x,0};
                                }
                            }
                        }
                    }
                    f[i][j][l][r][0][0]=val+add;
                    add=0;
                    for(int p=1;p<=l;p++)
                    {
                        for(int q=r;q<=m;q++)
                        {
                            for(int x=0;x<=1;x++)
                            {
                                for(int y=0;y<=1;y++)
                                {
                                    int tmp=f[i-1][j-(r-l+1)][p][q][x][y];
                                    if(tmp>add)
                                    {
                                        add=tmp;
                                        pre[i][j][l][r][0][1]=(node){i-1,j-(r-l+1),p,q,x,y};
                                    }
                                }
                            }
                        }
                    }
                    f[i][j][l][r][0][1]=add+val;
                }
            }
        }
    }
    int ans=0;
    node ans1;
    for(int i=1;i<=n;i++)
    {
        for(int l=1;l<=m;l++)
        {
            for(int r=l;r<=m;r++)
            {
                for(int x=0;x<=1;x++)
                {
                    for(int y=0;y<=1;y++)
                    {
                        int tmp=f[i][k][l][r][x][y];
                        if(tmp>ans)
                        {
                            ans=tmp;
                            ans1=(node){i,k,l,r,x,y};
                        }
                    }
                }
            }
        }
    }
    printf("Oil : %d\n",ans);
    print(ans1);
    return 0;
}
